module lfsr_32bit(
    input clk,
    input rst_n,
    input en,
    output [31:0] lfsr_out
);

    reg [31:0] unused_shift_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            unused_shift_reg <= 32'h1; // Non-zero seed value
        end else if (en) begin
            unused_shift_reg <= {unused_shift_reg[30:0], unused_shift_reg[31] ^ unused_shift_reg[21] ^ unused_shift_reg[1] ^ unused_shift_reg[0]};
        end
    end

    assign lfsr_out = unused_shift_reg;

endmodule
